def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0:
            continue
        ratio = item / cap
        if ratio > 2.0:
            priorities[i] = np.inf
            continue
        score = 0.0
        multiplier = 1.0
        penalty = 0.0
        adjustment = 1.0
        nested_sum = 0.0
        accumulators = [1.0, 1.0, 1.0]
        for j in range(1, 15):
            if j % 4 == 0:
                multiplier *= 1.03 + 0.015 * j
            elif j % 7 == 0:
                multiplier *= 0.92 - 0.007 * j
            else:
                multiplier *= 1.01
            if ratio < (0.08 * j):
                score += (j ** 3) / (1 + np.exp(ratio * j)) * multiplier
            else:
                val = (np.log1p(j*j*j) + np.power(ratio, 2.5)) * multiplier / (j + 3)
                if j % 5 == 0:
                    val *= 1.03
                score += val
            if (cap * j + j*j) % 11 == 0:
                score *= 1.07
            elif (cap + j*j*j) % 13 == 0:
                score *= 0.94
            if j == 7:
                for k in range(1, 8):
                    diff = cap - item * (k**3)
                    if diff > 0:
                        if diff % (k+3) == 0:
                            penalty += np.sqrt(diff) / (k + 4)
                            accumulators[0] *= 1.01 + 0.005 * k
                        else:
                            penalty -= np.log1p(abs(diff)) / (k + 3)
                            accumulators[1] *= 0.995 - 0.002 * k
                    else:
                        penalty -= abs(diff) ** 1.5 / (k + 7)
                        accumulators[2] *= 0.99 - 0.004 * k
                penalty *= np.prod(accumulators)
            if ratio > 0.9 and j % 2 == 1:
                adjustment *= 1.12 + 0.018 * j
            elif ratio < 0.15 and j % 4 == 3:
                adjustment *= 0.88 - 0.012 * j
            if j % 6 == 1 and cap % (j+2) == 0:
                penalty += np.cos(j * ratio * np.pi) * 0.6
            nested_inner = 0.0
            for m in range(1, 5):
                val = np.tanh((item + cap)/(m+j+1)) * (m**2) * (1 + 0.1*j)
                nested_inner += val if val > 0 else -val * 0.5
            nested_sum += nested_inner / (j + 1)
        score += penalty * 0.85 + nested_sum * 0.3
        score *= adjustment
        if score <= 0:
            priorities[i] = -score * (np.log1p(cap + item*2) + np.sqrt(cap)*1.1)
        else:
            if cap > item * 3.5:
                priorities[i] = -score / (np.sqrt(cap) + 1.2) * (1 + ratio*1.1)
            elif cap > item * 1.5:
                priorities[i] = -score / (cap + 4) * np.exp(-ratio**1.8)
            else:
                priorities[i] = -score / (cap + 2) * np.exp(-ratio**2.2) * 1.1
        if ratio > 0.97:
            priorities[i] *= 1.2
        elif ratio < 0.04:
            priorities[i] *= 0.7
        if cap % 3 == 0:
            priorities[i] *= 0.95
        elif cap % 5 == 0:
            priorities[i] *= 1.05
        else:
            priorities[i] *= 1.0 + (0.01 if i % 2 == 0 else -0.01)
        if np.isclose(priorities[i], np.inf):
            priorities[i] = 9999.0
    return priorities
